def solve(s: String): Array[String] = {
    val segments = scala.collection.mutable.ListBuffer[String]()
    val seen = scala.collection.mutable.Set[String]()
    var currentSegment = ""
    var currentIndex = 0
    while (currentIndex < s.length) {
        currentSegment += s(currentIndex)
        if (!seen.contains(currentSegment)) {
            seen += currentSegment
            segments += currentSegment
            currentSegment = ""
            currentIndex += 1
        } else {
            currentIndex += 1
        }
    }
    segments.toArray
}
